/* ============================================================
   BEspoke Sport — Global CSS
   ============================================================ */

:root {
  --bs-black:        #0D0D0D;
  --bs-card-dark:    #1A1A1A;
  --bs-white:        #F5F5F0;
  --bs-green:        #5DCAA5;
  --bs-green-dark:   #1D9E75;
  --bs-muted:        #888888;
  --bs-border-dark:  #2A2A2A;
  --bs-border-light: #E0E0D8;
  --bs-font:         'Inter', sans-serif;
  --bs-radius-sm:    4px;
  --bs-radius-md:    8px;
  --bs-radius-lg:    12px;
  --bs-transition:   0.22s ease;
}

*, *::before, *::after { box-sizing: border-box; }

body {
  font-family: var(--bs-font);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

img { display: block; max-width: 100%; }

h1, h2, h3, h4, h5, h6,
.elementor-heading-title {
  font-family: var(--bs-font);
  font-weight: 500;
  line-height: 1.15;
  letter-spacing: -0.02em;
}

.bs-eyebrow {
  font-family: var(--bs-font);
  font-size: 11px;
  font-weight: 500;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--bs-green);
}

.elementor-button.elementor-button-primary,
.bs-btn-primary {
  background-color: var(--bs-green) !important;
  color: #04342C !important;
  border: none !important;
  border-radius: var(--bs-radius-sm) !important;
  font-family: var(--bs-font) !important;
  font-size: 13px !important;
  font-weight: 500 !important;
  letter-spacing: 0.03em !important;
  padding: 14px 28px !important;
  transition: background-color var(--bs-transition), transform var(--bs-transition) !important;
}
.elementor-button.elementor-button-primary:hover,
.bs-btn-primary:hover {
  background-color: var(--bs-green-dark) !important;
  transform: translateY(-1px);
}

.elementor-button.elementor-button-ghost,
.bs-btn-ghost {
  background-color: transparent !important;
  color: var(--bs-white) !important;
  border: 0.5px solid rgba(255,255,255,0.35) !important;
  border-radius: var(--bs-radius-sm) !important;
  font-family: var(--bs-font) !important;
  font-size: 13px !important;
  font-weight: 400 !important;
  padding: 14px 28px !important;
  transition: border-color var(--bs-transition), background-color var(--bs-transition) !important;
}
.elementor-button.elementor-button-ghost:hover {
  background-color: rgba(255,255,255,0.07) !important;
  border-color: rgba(255,255,255,0.6) !important;
}

.elementor-widget-button .elementor-button {
  transition: all var(--bs-transition) !important;
}

.bs-dark {
  background-color: var(--bs-black) !important;
  color: var(--bs-white);
}
.bs-dark h1, .bs-dark h2, .bs-dark h3,
.bs-dark .elementor-heading-title {
  color: var(--bs-white) !important;
}
.bs-dark p,
.bs-dark .elementor-widget-text-editor {
  color: var(--bs-muted) !important;
}
.bs-dark p strong { color: var(--bs-white); }

.bs-accent { color: var(--bs-green) !important; }

.bs-section-cut::after {
  content: '';
  display: block;
  position: absolute;
  bottom: -1px;
  left: 0;
  right: 0;
  height: 80px;
  background: var(--bs-white);
  clip-path: polygon(0 100%, 100% 0, 100% 100%);
}
.bs-section-cut {
  position: relative;
  overflow: hidden;
}

.woocommerce ul.products li.product,
.woocommerce-page ul.products li.product {
  border: 0.5px solid var(--bs-border-light);
  border-radius: var(--bs-radius-lg);
  overflow: hidden;
  transition: transform var(--bs-transition), box-shadow var(--bs-transition);
  background: #fff;
}
.woocommerce ul.products li.product:hover,
.woocommerce-page ul.products li.product:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 32px rgba(0,0,0,0.08);
}

.woocommerce ul.products li.product .woocommerce-loop-product__title {
  font-family: var(--bs-font);
