.woocommerce div.product .product_title {
  font-family: var(--bs-font);
  font-size: 32px;
  font-weight: 500;
  letter-spacing: -0.02em;
  color: var(--bs-card-dark);
}

.woocommerce div.product p.price,
.woocommerce div.product span.price {
